	/**  全局 Java 可执行文件路径。`None` 表示让启动器自动探测/安装。 */
	java_path?: string | null,
	/**
	 *  是否启用下载镜像。即使 `download_source` 是官方,该开关也能强制走镜像;
	 *  二者任一指向镜像即生效(见 [`GlobalSettings::mirror_resolver`])。
	 */
	use_mirror?: boolean,
	/**  界面语言标签(如 `"zh-CN"`、`"en-US"`)。 */
