	instance_id: string,
	/**
	 *  可更新的已启用 mod 数量(`check_mod_updates` 结果的长度)。
	 *  **仅对非整合包实例(散装 / 手动装 mod)统计**;整合包实例恒为 0——它的 mod
	 *  跟随整合包版本走,由「整合包更新」统一驱动,不在这里单独报。
	 */
	mod_updates: number,
	/**  该实例(由整合包安装)是否有比当前来源版本更新的整合包版本(仅 Modrinth 来源可判定)。 */
