/**
 *  JavaInstall with the version flattened to a string (the core keeps it
 *  structured; the UI only displays it).
 */
export type JavaDto = {
	path: string,
	version: string,
	is_64bit: boolean,
	source: string,
};

/**
 *  A specta-exportable stand-in for arbitrary JSON (`serde_json::Value`), used
 *  only as the export type of [`AgentStreamEvent::ToolCall`]'s `args` field.
 * 
 *  specta registers `serde_json::Value` as an *inline* type, and since it is
 *  recursive (`Value` → `Vec<Value>` → `Value`) specta-typescript refuses to
 *  inline it — so any exported DTO carrying a bare `serde_json::Value` fails to
 *  generate. This named, self-referential enum exports cleanly as a recursive
 *  `JsonValue` union instead. It never participates in (de)serialization of an
 *  event — the real field stays `serde_json::Value` — so the wire format is
 *  unchanged; this type exists purely to shape the generated TypeScript.
 */
export type JsonValue = "Null" | boolean | number | null | string | JsonValue[] | { [key in string]: JsonValue };

/**  记住的一个 kobeMC 账号凭据。`auto_login` 为真的(至多一个)启动时自动登录。 */
export type KobeCredentials = {
	email: string,
	password: string,
	auto_login?: boolean,
};

/**  Mod loader families. */
export type LoaderKind = "vanilla" | "forge" | "neoforge" | "fabric" | "quilt" | "liteloader" | "optifine";

/**
 *  一个 loader(`GET /tag/loader` 的一项)。`supported_project_types` 指出该 loader
 *  适用于哪些资源类型(过滤面板据此只在相关 kind 下显示对应 loader)。
 */
export type LoaderTag = {
	name: string,
	supported_project_types: string[],
};

/**  某领域的联机大厅凭据(EasyTier 房间)。 */
export type LobbyCreds = {
	network_name: string,
	network_secret: string,
	nodes?: LobbyNode[],
};

/**
 *  一个 EasyTier external/relay 节点。`kind`:`"p2p"` = 公共共享节点(打洞后直连,我们零成本);
 *  `"hosted"` = 我们自建的中继(host 点,打洞失败时兜底)。
 */
export type LobbyNode = {
	kind: string,
	name: string,
	addr: string,
};

/**  `easytier-cli peer` 表里的一行(一个对端,或本机自己那行)。 */
export type LobbyPeer = {
	ipv4: string | null,
	hostname: string,
	cost: string,
	lat_ms: number | null,
	nat_type: string | null,
};

/**  联机大厅当前状态:是否在跑、本机虚拟 IP、对端列表(不含本机自己那行)。 */
export type LobbyStatus = {
	running: boolean,
	virtual_ip: string | null,
	peers: LobbyPeer[],
};

/**  One entry from Mojang's version manifest. */
export type ManifestVersion = {
	id: string,
	kind: ReleaseKind,
	url: string,
	/**  SHA1 of the version json (Mojang manifest_v2 provides this). */
	sha1?: string,
	/**  ISO-8601 release time. */
	release_time?: string,
};

/**  单个本地 mod 的元数据视图。字段尽量贴近 UI 列表展示所需。 */
export type ModInfo = {
	/**  磁盘上的实际文件名(含 `.disabled` 后缀,如有)。用作启停/删除的稳定标识。 */
	file_name: string,
	/**  是否启用 = 文件名不以 `.disabled` 结尾。 */
	enabled: boolean,
	/**  展示名;读不到元数据时回退为去掉扩展名的文件名。 */
	name: string,
	/**  版本号(部分 mod 用占位符如 `${version}`,原样保留)。 */
	version: string | null,
	/**  mod 内部 id(fabric `id` / quilt `id` / forge `modId`)。 */
	mod_id: string | null,
	/**  loader 家族:`fabric` / `quilt` / `forge` / `neoforge` / `unknown`。 */
	loader: string,
	/**  作者列表(各 loader 格式差异较大,这里统一拍平成字符串数组)。 */
	authors: string[],
	/**  描述(通常为一句话)。 */
	description: string | null,
	/**  文件字节大小。 */
	size: number,
};

/**
 *  「装最新版」mod 的结果:沿用核心的依赖解析报告,再带上需手动下载的 blocked 文件
 *  (CurseForge 作者禁第三方分发时)。`blocked` 非空时前端弹 BlockedFilesDialog 引导手动下。
 */
export type ModInstallReport = {
	installed: InstalledMod[],
	satisfied: string[],
	unresolved: string[],
	incompatible?: string[],
	blocked?: BlockedFileDto[],
};

/**
 *  一个可用的 mod 更新。携带应用更新所需的全部信息(下载地址 / 校验 / 目标文件名),
 *  这样 UI 拿到后无需再查一次即可直接调用 [`apply_mod_update`]。
 */
export type ModUpdate = {
	/**  当前磁盘上的文件名(启用态 `.jar`),应用更新后会被替换/删除。 */
	file_name: string,
	/**  展示名(取本地解析到的 mod 名,读不到时为文件名)。 */
	name: string,
	/**  当前版本号(本地元数据;可能缺失)。 */
	current_version: string | null,
	/**  最新版本号(Modrinth `version_number`)。 */
	new_version: string,
	/**  最新版本主文件的文件名(下载后的落盘名)。 */
	new_file_name: string,
	/**  下载地址。 */
	url: string,
	/**  最新文件 sha1(下载校验用;Modrinth 通常都提供)。 */
	sha1: string | null,
	/**  最新文件大小(字节)。 */
	size: number | null,
};

