	/**  是否启用(= 不以 `.disabled` 结尾)。 */
	enabled: boolean,
	/**  资源类型标签(`resourcepack` / `shader` / `datapack`),来自 [`PackKind::label`]。 */
	kind: string,
	/**  文件大小(字节);目录形态的数据包为 0(不递归求和,避免大目录扫描开销)。 */
